const d = $input.first().json;

// ── Default DCF assumptions (override via webhook body if provided) ──
const assumptions = {
  projectionYears:                          d.projectionYears                          || 5,
  revenueGrowthRate:                        d.revenueGrowthRate                        || 12,
  ebitMargin:                               d.ebitMargin                               || 15,
  taxRate:                                  d.taxRate                                  || 25,
  capexAsPercentRevenue:                    d.capexAsPercentRevenue                    || 5,
  workingCapitalChangeAsPercentRevenue:     d.workingCapitalChangeAsPercentRevenue     || 2,
  wacc:                                     d.wacc                                     || 12,
  terminalGrowthRate:                       d.terminalGrowthRate                       || 4,
};

const netDebt =
  (d.totalDebt?.[d.totalDebt.length - 1]         || 0) -
  (d.cashAndEquivalents?.[d.cashAndEquivalents.length - 1] || 0);

const sharesOutstanding = d.sharesOutstanding || 1;

// ── Projections ──
const projections = [];
let revenue = d.revenue?.[d.revenue.length - 1] || 0;

for (let i = 1; i <= assumptions.projectionYears; i++) {
  revenue = revenue * (1 + assumptions.revenueGrowthRate / 100);
  const ebit        = revenue * (assumptions.ebitMargin / 100);
  const nopat       = ebit * (1 - assumptions.taxRate / 100);
  const depreciation = revenue * 0.03;
  const capex       = revenue * (assumptions.capexAsPercentRevenue / 100);
  const wcChange    = revenue * (assumptions.workingCapitalChangeAsPercentRevenue / 100);
  const fcf         = nopat + depreciation - capex - wcChange;
  const df          = Math.pow(1 + assumptions.wacc / 100, i);

  projections.push({
    year:                  new Date().getFullYear() + i,
    revenue:               Math.round(revenue),
    ebit:                  Math.round(ebit),
    nopat:                 Math.round(nopat),
    depreciation:          Math.round(depreciation),
    capex:                 Math.round(capex),
    workingCapitalChange:  Math.round(wcChange),
    freeCashFlow:          Math.round(fcf),
    discountFactor:        parseFloat(df.toFixed(4)),
    presentValue:          Math.round(fcf / df),
  });
}

const sumPV      = projections.reduce((s, p) => s + p.presentValue, 0);
const lastFCF    = projections[projections.length - 1].freeCashFlow;
const tv         = lastFCF * (1 + assumptions.terminalGrowthRate / 100) /
                   ((assumptions.wacc - assumptions.terminalGrowthRate) / 100);
const pvTV       = Math.round(tv / Math.pow(1 + assumptions.wacc / 100, assumptions.projectionYears));
const ev         = Math.round(sumPV + pvTV);
const equity     = Math.round(ev - netDebt);
const ivps       = parseFloat((equity / sharesOutstanding).toFixed(2));

return [{
  json: {
    // metadata
    companyName:              d.companyName,
    reportYear:               d.reportYear,
    currency:                 d.currency || 'INR',
    _requesterEmail:          d._requesterEmail || '',
    _uploadedAt:              d._uploadedAt,
    _calculatedAt:            new Date().toISOString(),
    // assumptions used
    assumptions,
    // results
    projections,
    terminalValue:            Math.round(tv),
    presentValueTerminalValue: pvTV,
    sumPVFreeCashFlows:       Math.round(sumPV),
    enterpriseValue:          ev,
    netDebt:                  Math.round(netDebt),
    equityValue:              equity,
    sharesOutstanding,
    intrinsicValuePerShare:   ivps,
  }
}];

